import{bQ as a,aL as t,u as s,G as i}from"./chunks/framework.D06dwy5q.js";const r=JSON.parse('{"title":"01｜为什么要学 Linux，登录后看到什么","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/01-为什么要学Linux登录后看到什么.md","filePath":"01.Linux基础/01-为什么要学Linux登录后看到什么.md","lastUpdated":null}'),o={name:"01.Linux基础/01-为什么要学Linux登录后看到什么.md"};function d(n,e,p,c,l,h){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_01-为什么要学-linux-登录后看到什么" tabindex="-1">01｜为什么要学 Linux，登录后看到什么 <a class="header-anchor" href="#_01-为什么要学-linux-登录后看到什么" aria-label="Permalink to &quot;01｜为什么要学 Linux，登录后看到什么&quot;">​</a></h1><p>打开手机点开一个 App，或者电脑浏览器打开一个网站，背后都有一台（或很多台）机器在跑程序、存数据、返回内容。这些机器上运行的系统，绝大部分是 Linux。</p><p>这套教程要学的，就是 Linux 这套系统怎么用——怎么登录、怎么敲命令、怎么管理它。本篇先讲清楚为什么要学它、它有哪些种类，最后登录一台 Linux 看看机器长什么样。</p><h2 id="一、后台跑的为什么是-linux" tabindex="-1">一、后台跑的为什么是 Linux <a class="header-anchor" href="#一、后台跑的为什么是-linux" aria-label="Permalink to &quot;一、后台跑的为什么是 Linux&quot;">​</a></h2><p>桌面电脑和笔记本上，大部分人用的是 Windows 或 macOS。但服务器（专门提供服务、24 小时开着的那种机器）上，绝大多数跑的是 Linux。</p><p>差别在哪。Windows 和 macOS 是给&quot;坐在屏幕前用鼠标&quot;的人设计的，默认带图形界面。图形界面好看，但占资源——一个图形界面要占几百 MB 内存，服务器上没人坐在屏幕前看，这些资源白费了。服务器要的是把资源尽量留给业务程序用。</p><p>Linux 可以不装图形界面，纯命令行运行。一台 Linux 服务器开机后就是个黑底白字的终端，敲命令操作。没有桌面、没有窗口，省下来的内存和 CPU 全给业务程序。远程管理也轻——一条命令传过去就行，不用传图形画面。</p><p>还有成本。Windows Server 是要花钱买授权的，一台机器一份。Linux 是开源的，免费，装多少台都不要钱。企业要部署成百上千台服务器，这笔钱差别很大。</p><p>这两条合起来——资源省、免费——让 Linux 成了服务器的默认选择。运维、后端开发、测试、数据这些岗位，只要碰服务器，就得懂 Linux。</p><h2 id="二、linux-有哪些种类" tabindex="-1">二、Linux 有哪些种类 <a class="header-anchor" href="#二、linux-有哪些种类" aria-label="Permalink to &quot;二、Linux 有哪些种类&quot;">​</a></h2><p>Linux 不是一家公司做的统一产品，它是一个内核加上各种外围软件的组合。不同的组织把内核和软件打包成不同发行版（distribution，常叫 distro）。所以&quot;装 Linux&quot;实际是装某个发行版。</p><p>常见发行版分两个家族：</p><table tabindex="0"><thead><tr><th>家族</th><th>常见成员</th><th>包管理命令</th></tr></thead><tbody><tr><td>RHEL 系</td><td>RHEL、CentOS、Rocky、AlmaLinux</td><td><code>yum</code> / <code>dnf</code></td></tr><tr><td>Debian 系</td><td>Debian、Ubuntu</td><td><code>apt</code></td></tr></tbody></table><p>两个家族的差别主要在&quot;怎么装软件&quot;这件事上。RHEL 系用 <code>yum</code>（新版叫 <code>dnf</code>）装软件包，Debian 系用 <code>apt</code>。命令不一样，软件包格式也不一样（<code>.rpm</code> vs <code>.deb</code>），但装完之后软件本身是一样的。</p><p>企业服务器里 RHEL 系和 Debian 系都常见。国内云上 CentOS 历史占比很高（不过 CentOS 已经停止维护，现在多换成了 Rocky、AlmaLinux 这些接替者），Ubuntu 在创业公司和容器场景多。具体学哪个不影响——命令行操作、文件系统、进程管理这些是共通的，会一个就能上手另一个。</p><p>还有一点要知道：这些发行版都用 <code>systemd</code> 管理服务（启动、停止、开机自启）。所以 <code>systemctl</code> 这套命令在两个家族里是一样的，不用分别记。</p><h2 id="三、登录一台机器看看" tabindex="-1">三、登录一台机器看看 <a class="header-anchor" href="#三、登录一台机器看看" aria-label="Permalink to &quot;三、登录一台机器看看&quot;">​</a></h2><p>光讲概念没用，登录一台 Linux 看看它实际长什么样。</p><p>如果手头有台云服务器，用 ssh 登录。如果没有，本地装个 Linux 虚拟机、或者用 WSL（Windows 里的 Linux 子系统）都行。登录后看到的是一个提示符，通常是这种样子：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[root@localhost ~]#</span></span></code></pre></div><p>或者：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>deploy@web-01:~$</span></span></code></pre></div><p>提示符里已经藏了几条信息：<code>root</code> / <code>deploy</code> 是当前登录的用户名，<code>localhost</code> / <code>web-01</code> 是这台机器的名字，<code>~</code> 是当前所在目录（家目录）。一个提示符就能看出&quot;我是谁、在哪台机器、在哪个目录&quot;。</p><p>先敲几个最基础的命令，看看机器长什么样：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mon Jun 23 14:38:21 CST 2026</span></span></code></pre></div><p><code>date</code> 显示当前时间。如果这个时间和手表对不上，多半是时区没设对——后面专门讲。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root</span></span></code></pre></div><p><code>whoami</code> 显示当前登录的用户名。看到 <code>root</code> 要注意——root 是管理员账号，权限最大，敲错命令可能删掉整个系统。生产环境里通常不用 root 直接干活，而是用一个普通账号，需要权限时再 <code>sudo</code> 提权。这台机器现在是 root，教程练习没问题，生产里要小心。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/root</span></span></code></pre></div><p><code>pwd</code> 显示当前所在目录。<code>/root</code> 是 root 用户的家目录。普通用户的家目录一般在 <code>/home/用户名</code> 下面。</p><p>再看一眼机器根目录下有什么：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bin  boot  dev  etc  home  lib  lib64  media  mnt  opt  proc  root  run  sbin  srv  sys  tmp  usr  var</span></span></code></pre></div><p>一堆目录名。这些是 Linux 文件系统的标准布局，每个目录放特定类型的东西。比如 <code>/etc</code> 放配置文件，<code>/var/log</code> 放日志，<code>/home</code> 放用户文件。这些后面会专门讲，不用现在背——先知道根目录下有这么些目录就行。</p><h2 id="四、本系列会学到什么" tabindex="-1">四、本系列会学到什么 <a class="header-anchor" href="#四、本系列会学到什么" aria-label="Permalink to &quot;四、本系列会学到什么&quot;">​</a></h2><p>到目前为止，登录一台 Linux、敲了 <code>date</code>、<code>whoami</code>、<code>pwd</code>、<code>ls /</code>，已经能看出这台机器的一些信息了。但这只是个开始。</p><p>接下来的几篇会依次讲：怎么在命令行里操作文件（增删改查、移动复制）、怎么用编辑器改配置、怎么管用户和权限、怎么管进程、怎么看磁盘和内存。这些都是日常运维和开发里反复要用的基础操作。</p><p>再往后会讲怎么把这些操作组织成脚本（让机器自动干活）、怎么远程登录和传文件、怎么初始化一台新服务器、怎么部署服务。</p><p>这套教程的目的不是让读者背命令，是让读者能独立操作一台 Linux 机器——知道要做什么时能敲出来，出了问题能查、能修。</p>',42)])])}const b=a(o,[["render",d]]);export{r as __pageData,b as default};
